-- ================================================================
--                    SYSTEM TABLE
-- ================================================================

-- AI agent query audit log
CREATE TABLE IF NOT EXISTS ai_query_log (
    log_id                       SERIAL PRIMARY KEY,
    user_query                   TEXT,
    detected_domain              VARCHAR(30),
    generated_sql                TEXT,
    response_summary             TEXT,
    execution_time_ms            INTEGER,
    created_at                TIMESTAMP DEFAULT NOW()
);


-- ================================================================
--                    HCM DOMAIN (22 TABLES)
-- ================================================================

-- H1: Core person identity -- no org/job context here
CREATE TABLE IF NOT EXISTS hcm_persons (
    person_id                    SERIAL PRIMARY KEY,
    person_number                VARCHAR(20) UNIQUE NOT NULL,
    first_name                   VARCHAR(80) NOT NULL,
    last_name                    VARCHAR(80) NOT NULL,
    date_of_birth                DATE,
    gender                       VARCHAR(10),
    nationality                  VARCHAR(50),
    national_id                  VARCHAR(30),
    marital_status               VARCHAR(20),
    person_type                  VARCHAR(20) DEFAULT 'EMPLOYEE',
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW(),
    updated_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_persons_status ON hcm_persons(status);
CREATE INDEX IF NOT EXISTS idx_hcm_persons_person_number ON hcm_persons(person_number);


-- H2: Historical person names (legal name changes)
CREATE TABLE IF NOT EXISTS hcm_person_names (
    person_name_id               SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    name_type                    VARCHAR(20) DEFAULT 'GLOBAL',
    title                        VARCHAR(10),
    first_name                   VARCHAR(80) NOT NULL,
    middle_name                  VARCHAR(80),
    last_name                    VARCHAR(80) NOT NULL,
    suffix                       VARCHAR(10),
    effective_from               DATE NOT NULL,
    effective_to                 DATE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_person_names_person_id ON hcm_person_names(person_id);


-- H3: Person email addresses
CREATE TABLE IF NOT EXISTS hcm_person_emails (
    email_id                     SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    email_type                   VARCHAR(20) DEFAULT 'WORK',
    email_address                VARCHAR(150) NOT NULL,
    is_primary                   BOOLEAN DEFAULT TRUE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_person_emails_person_id ON hcm_person_emails(person_id);


-- H4: Business units and legal entities (self-ref hierarchy)
CREATE TABLE IF NOT EXISTS hcm_organizations (
    org_id                       SERIAL PRIMARY KEY,
    org_code                     VARCHAR(20) UNIQUE NOT NULL,
    org_name                     VARCHAR(150) NOT NULL,
    org_type                     VARCHAR(30) DEFAULT 'BUSINESS_UNIT',
    parent_org_id                INTEGER REFERENCES hcm_organizations(org_id),
    country                      VARCHAR(50) DEFAULT 'United Kingdom',
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    effective_from               DATE DEFAULT CURRENT_DATE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_organizations_parent_org_id ON hcm_organizations(parent_org_id);


-- H5: Office and work locations
CREATE TABLE IF NOT EXISTS hcm_locations (
    location_id                  SERIAL PRIMARY KEY,
    location_code                VARCHAR(20) UNIQUE NOT NULL,
    location_name                VARCHAR(100) NOT NULL,
    address_line1                VARCHAR(200),
    city                         VARCHAR(50),
    region                       VARCHAR(30),
    postal_code                  VARCHAR(15),
    country                      VARCHAR(50) DEFAULT 'United Kingdom',
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- H6: Department master (FK→org; manager FK deferred to avoid circularity)
CREATE TABLE IF NOT EXISTS hcm_departments (
    dept_id                      SERIAL PRIMARY KEY,
    dept_code                    VARCHAR(20) UNIQUE NOT NULL,
    dept_name                    VARCHAR(100) NOT NULL,
    org_id                       INTEGER REFERENCES hcm_organizations(org_id),
    cost_centre_code             VARCHAR(20),
    manager_person_id            INTEGER,
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_departments_org_id ON hcm_departments(org_id);


-- H7: Job catalog / families
CREATE TABLE IF NOT EXISTS hcm_jobs (
    job_id                       SERIAL PRIMARY KEY,
    job_code                     VARCHAR(20) UNIQUE NOT NULL,
    job_name                     VARCHAR(100) NOT NULL,
    job_family                   VARCHAR(50),
    job_level                    VARCHAR(20),
    min_salary                   NUMERIC(12,2),
    max_salary                   NUMERIC(12,2),
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- H8: Grade ranges and salary bands
CREATE TABLE IF NOT EXISTS hcm_grades (
    grade_id                     SERIAL PRIMARY KEY,
    grade_code                   VARCHAR(10) UNIQUE NOT NULL,
    grade_name                   VARCHAR(50) NOT NULL,
    min_salary                   NUMERIC(12,2),
    mid_salary                   NUMERIC(12,2),
    max_salary                   NUMERIC(12,2),
    currency                     VARCHAR(3) DEFAULT 'GBP',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- H9: Position definitions (slot in org chart)
CREATE TABLE IF NOT EXISTS hcm_positions (
    position_id                  SERIAL PRIMARY KEY,
    position_code                VARCHAR(20) UNIQUE NOT NULL,
    position_name                VARCHAR(100) NOT NULL,
    dept_id                      INTEGER REFERENCES hcm_departments(dept_id),
    job_id                       INTEGER REFERENCES hcm_jobs(job_id),
    location_id                  INTEGER REFERENCES hcm_locations(location_id),
    grade_id                     INTEGER REFERENCES hcm_grades(grade_id),
    headcount_target             INTEGER DEFAULT 1,
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_positions_dept_id ON hcm_positions(dept_id);
CREATE INDEX IF NOT EXISTS idx_hcm_positions_job_id ON hcm_positions(job_id);
CREATE INDEX IF NOT EXISTS idx_hcm_positions_location_id ON hcm_positions(location_id);
CREATE INDEX IF NOT EXISTS idx_hcm_positions_grade_id ON hcm_positions(grade_id);


-- H10: Assignment-based modeling -- ALL org context lives here
CREATE TABLE IF NOT EXISTS hcm_assignments (
    assignment_id                SERIAL PRIMARY KEY,
    assignment_number            VARCHAR(20) UNIQUE NOT NULL,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    position_id                  INTEGER REFERENCES hcm_positions(position_id),
    dept_id                      INTEGER REFERENCES hcm_departments(dept_id),
    org_id                       INTEGER REFERENCES hcm_organizations(org_id),
    grade_id                     INTEGER REFERENCES hcm_grades(grade_id),
    job_id                       INTEGER REFERENCES hcm_jobs(job_id),
    location_id                  INTEGER REFERENCES hcm_locations(location_id),
    assignment_type              VARCHAR(20) DEFAULT 'PRIMARY',
    assignment_status            VARCHAR(20) DEFAULT 'ACTIVE',
    employment_status            VARCHAR(20) DEFAULT 'ACTIVE',
    job_title                    VARCHAR(100),
    salary                       NUMERIC(12,2),
    salary_currency              VARCHAR(3) DEFAULT 'GBP',
    manager_person_id            INTEGER REFERENCES hcm_persons(person_id),
    effective_from               DATE NOT NULL,
    effective_to                 DATE,
    created_at                TIMESTAMP DEFAULT NOW(),
    updated_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_assignments_person_id ON hcm_assignments(person_id);
CREATE INDEX IF NOT EXISTS idx_hcm_assignments_position_id ON hcm_assignments(position_id);
CREATE INDEX IF NOT EXISTS idx_hcm_assignments_dept_id ON hcm_assignments(dept_id);
CREATE INDEX IF NOT EXISTS idx_hcm_assignments_org_id ON hcm_assignments(org_id);
CREATE INDEX IF NOT EXISTS idx_hcm_assignments_manager_person_id ON hcm_assignments(manager_person_id);


-- H11: Employment period spans (hire-to-terminate window)
CREATE TABLE IF NOT EXISTS hcm_employment_periods (
    employment_period_id         SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    period_type                  VARCHAR(20) DEFAULT 'EMPLOYEE',
    start_date                   DATE NOT NULL,
    end_date                     DATE,
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_employment_periods_person_id ON hcm_employment_periods(person_id);


-- H12: Termination reason lookup
CREATE TABLE IF NOT EXISTS hcm_termination_reasons (
    reason_id                    SERIAL PRIMARY KEY,
    reason_code                  VARCHAR(20) UNIQUE NOT NULL,
    reason_name                  VARCHAR(100) NOT NULL,
    reason_category              VARCHAR(30),
    is_voluntary                 BOOLEAN DEFAULT TRUE,
    created_at                TIMESTAMP DEFAULT NOW()
);


-- H13: Workforce lifecycle actions (hire/transfer/promote/terminate)
CREATE TABLE IF NOT EXISTS hcm_workforce_actions (
    action_id                    SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id),
    action_type                  VARCHAR(30) NOT NULL,
    action_reason                VARCHAR(100),
    effective_date               DATE NOT NULL,
    reason_id                    INTEGER REFERENCES hcm_termination_reasons(reason_id),
    old_value                    VARCHAR(200),
    new_value                    VARCHAR(200),
    processed_by                 INTEGER REFERENCES hcm_persons(person_id),
    status                       VARCHAR(20) DEFAULT 'COMPLETED',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_workforce_actions_person_id ON hcm_workforce_actions(person_id);
CREATE INDEX IF NOT EXISTS idx_hcm_workforce_actions_assignment_id ON hcm_workforce_actions(assignment_id);


-- H14: Promotion history linked to assignment
CREATE TABLE IF NOT EXISTS hcm_promotions (
    promotion_id                 SERIAL PRIMARY KEY,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    effective_date               DATE NOT NULL,
    old_grade                    VARCHAR(10),
    new_grade                    VARCHAR(10),
    old_job_title                VARCHAR(100),
    new_job_title                VARCHAR(100),
    old_salary                   NUMERIC(12,2),
    new_salary                   NUMERIC(12,2),
    approved_by                  INTEGER REFERENCES hcm_persons(person_id),
    status                       VARCHAR(20) DEFAULT 'APPROVED',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_promotions_assignment_id ON hcm_promotions(assignment_id);


-- H15: Transfer history linked to assignment
CREATE TABLE IF NOT EXISTS hcm_transfers (
    transfer_id                  SERIAL PRIMARY KEY,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    effective_date               DATE NOT NULL,
    from_dept_id                 INTEGER REFERENCES hcm_departments(dept_id),
    to_dept_id                   INTEGER REFERENCES hcm_departments(dept_id),
    from_location_id             INTEGER REFERENCES hcm_locations(location_id),
    to_location_id               INTEGER REFERENCES hcm_locations(location_id),
    transfer_reason              VARCHAR(100),
    approved_by                  INTEGER REFERENCES hcm_persons(person_id),
    status                       VARCHAR(20) DEFAULT 'APPROVED',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_transfers_assignment_id ON hcm_transfers(assignment_id);


-- H16: Salary change history per assignment
CREATE TABLE IF NOT EXISTS hcm_salary_history (
    salary_history_id            SERIAL PRIMARY KEY,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    old_salary                   NUMERIC(12,2),
    new_salary                   NUMERIC(12,2) NOT NULL,
    change_reason                VARCHAR(50),
    effective_date               DATE NOT NULL,
    currency                     VARCHAR(3) DEFAULT 'GBP',
    approved_by                  INTEGER REFERENCES hcm_persons(person_id),
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_salary_history_assignment_id ON hcm_salary_history(assignment_id);


-- H17: Pay components (base, bonus, allowances) per assignment
CREATE TABLE IF NOT EXISTS hcm_compensation_elements (
    element_id                   SERIAL PRIMARY KEY,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    element_type                 VARCHAR(30) NOT NULL,
    element_name                 VARCHAR(100) NOT NULL,
    amount                       NUMERIC(12,2) NOT NULL,
    frequency                    VARCHAR(20) DEFAULT 'MONTHLY',
    currency                     VARCHAR(3) DEFAULT 'GBP',
    effective_from               DATE,
    effective_to                 DATE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_compensation_elements_assignment_id ON hcm_compensation_elements(assignment_id);


-- H18: Payroll batch run headers
CREATE TABLE IF NOT EXISTS hcm_payroll_runs (
    payroll_run_id               SERIAL PRIMARY KEY,
    run_name                     VARCHAR(100) NOT NULL,
    period_name                  VARCHAR(20) NOT NULL,
    run_date                     DATE NOT NULL,
    status                       VARCHAR(20) DEFAULT 'COMPLETED',
    total_gross                  NUMERIC(15,2),
    total_deductions             NUMERIC(15,2),
    total_net                    NUMERIC(15,2),
    employee_count               INTEGER,
    created_at                TIMESTAMP DEFAULT NOW()
);


-- H19: Individual payroll results per assignment per run
CREATE TABLE IF NOT EXISTS hcm_payroll_results (
    result_id                    SERIAL PRIMARY KEY,
    payroll_run_id               INTEGER REFERENCES hcm_payroll_runs(payroll_run_id) ON DELETE RESTRICT,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    gross_pay                    NUMERIC(12,2),
    tax_deducted                 NUMERIC(12,2),
    ni_deducted                  NUMERIC(12,2),
    pension_deducted             NUMERIC(12,2),
    other_deductions             NUMERIC(12,2) DEFAULT 0,
    net_pay                      NUMERIC(12,2),
    account_code_id              INTEGER,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_payroll_results_payroll_run_id ON hcm_payroll_results(payroll_run_id);
CREATE INDEX IF NOT EXISTS idx_hcm_payroll_results_assignment_id ON hcm_payroll_results(assignment_id);


-- H20: Assignment cost allocation to finance cost centres (cross-domain)
CREATE TABLE IF NOT EXISTS hcm_cost_allocations (
    allocation_id                SERIAL PRIMARY KEY,
    assignment_id                INTEGER REFERENCES hcm_assignments(assignment_id) ON DELETE RESTRICT,
    cost_centre_id               INTEGER,
    allocation_pct               NUMERIC(5,2) DEFAULT 100.00,
    effective_from               DATE NOT NULL,
    effective_to                 DATE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_cost_allocations_assignment_id ON hcm_cost_allocations(assignment_id);


-- H21: Performance reviews linked to person
CREATE TABLE IF NOT EXISTS hcm_performance_reviews (
    review_id                    SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    reviewer_person_id           INTEGER REFERENCES hcm_persons(person_id),
    review_period                VARCHAR(20) NOT NULL,
    review_type                  VARCHAR(20) DEFAULT 'ANNUAL',
    overall_rating               VARCHAR(30),
    rating_score                 NUMERIC(3,1),
    goals_met_pct                NUMERIC(5,2),
    comments                     TEXT,
    status                       VARCHAR(20) DEFAULT 'COMPLETED',
    review_date                  DATE,
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_performance_reviews_person_id ON hcm_performance_reviews(person_id);


-- H22: Training and certification records
CREATE TABLE IF NOT EXISTS hcm_training_records (
    training_id                  SERIAL PRIMARY KEY,
    person_id                    INTEGER REFERENCES hcm_persons(person_id) ON DELETE RESTRICT,
    course_name                  VARCHAR(150) NOT NULL,
    course_category              VARCHAR(50),
    provider                     VARCHAR(100),
    completion_date              DATE,
    score                        NUMERIC(5,2),
    status                       VARCHAR(20) DEFAULT 'COMPLETED',
    certificate_id               VARCHAR(50),
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_hcm_training_records_person_id ON hcm_training_records(person_id);


-- ================================================================
--                    FINANCE DOMAIN (23 TABLES)
-- ================================================================

-- F1: General ledger definitions
CREATE TABLE IF NOT EXISTS fin_ledgers (
    ledger_id                    SERIAL PRIMARY KEY,
    ledger_code                  VARCHAR(20) UNIQUE NOT NULL,
    ledger_name                  VARCHAR(100) NOT NULL,
    currency                     VARCHAR(3) DEFAULT 'GBP',
    calendar_type                VARCHAR(20) DEFAULT 'FISCAL',
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- F2: Chart of accounts structure
CREATE TABLE IF NOT EXISTS fin_chart_of_accounts (
    coa_id                       SERIAL PRIMARY KEY,
    coa_code                     VARCHAR(20) UNIQUE NOT NULL,
    coa_name                     VARCHAR(100) NOT NULL,
    ledger_id                    INTEGER REFERENCES fin_ledgers(ledger_id),
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_chart_of_accounts_ledger_id ON fin_chart_of_accounts(ledger_id);


-- F3: COA segment definitions (company, dept, account, etc.)
CREATE TABLE IF NOT EXISTS fin_coa_segments (
    segment_id                   SERIAL PRIMARY KEY,
    coa_id                       INTEGER REFERENCES fin_chart_of_accounts(coa_id) ON DELETE RESTRICT,
    segment_name                 VARCHAR(50) NOT NULL,
    segment_number               INTEGER NOT NULL,
    segment_type                 VARCHAR(30),
    value_set                    VARCHAR(50),
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_coa_segments_coa_id ON fin_coa_segments(coa_id);


-- F4: Cost centre master (cross-domain link to HCM)
CREATE TABLE IF NOT EXISTS fin_cost_centres (
    cost_centre_id               SERIAL PRIMARY KEY,
    cost_centre_code             VARCHAR(20) UNIQUE NOT NULL,
    cost_centre_name             VARCHAR(100) NOT NULL,
    dept_id                      INTEGER REFERENCES hcm_departments(dept_id),
    manager_person_id            INTEGER REFERENCES hcm_persons(person_id),
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_cost_centres_dept_id ON fin_cost_centres(dept_id);


-- Deferred FK: hcm_cost_allocations → fin_cost_centres
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname='fk_hcm_ca_cc') THEN
    ALTER TABLE hcm_cost_allocations ADD CONSTRAINT fk_hcm_ca_cc
      FOREIGN KEY (cost_centre_id) REFERENCES fin_cost_centres(cost_centre_id) ON DELETE RESTRICT;
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_hcm_cost_allocations_cost_centre_id ON hcm_cost_allocations(cost_centre_id);


-- F5: Account code master
CREATE TABLE IF NOT EXISTS fin_account_codes (
    account_code_id              SERIAL PRIMARY KEY,
    account_code                 VARCHAR(20) UNIQUE NOT NULL,
    account_name                 VARCHAR(100) NOT NULL,
    account_type                 VARCHAR(30) NOT NULL,
    parent_account_code          VARCHAR(20),
    coa_id                       INTEGER REFERENCES fin_chart_of_accounts(coa_id),
    status                       VARCHAR(20) DEFAULT 'ACTIVE',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_account_codes_coa_id ON fin_account_codes(coa_id);

-- Deferred FK: hcm_payroll_results → fin_account_codes
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname='fk_hcm_pr_ac') THEN
    ALTER TABLE hcm_payroll_results ADD CONSTRAINT fk_hcm_pr_ac
      FOREIGN KEY (account_code_id) REFERENCES fin_account_codes(account_code_id) ON DELETE RESTRICT;
  END IF;
END $$;
CREATE INDEX IF NOT EXISTS idx_hcm_payroll_results_account_code_id ON hcm_payroll_results(account_code_id);


-- F6: Fiscal reporting periods
CREATE TABLE IF NOT EXISTS fin_reporting_periods (
    period_id                    SERIAL PRIMARY KEY,
    period_name                  VARCHAR(20) UNIQUE NOT NULL,
    fiscal_year                  INTEGER NOT NULL,
    fiscal_quarter               INTEGER NOT NULL,
    period_number                INTEGER NOT NULL,
    start_date                   DATE NOT NULL,
    end_date                     DATE NOT NULL,
    status                       VARCHAR(20) DEFAULT 'OPEN',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- F7: Currency exchange rates
CREATE TABLE IF NOT EXISTS fin_currency_rates (
    rate_id                      SERIAL PRIMARY KEY,
    from_currency                VARCHAR(3) NOT NULL,
    to_currency                  VARCHAR(3) NOT NULL,
    exchange_rate                NUMERIC(12,6) NOT NULL,
    rate_type                    VARCHAR(20) DEFAULT 'SPOT',
    effective_date               DATE NOT NULL,
    created_at                TIMESTAMP DEFAULT NOW()
);


-- F8: GL journal entry headers
CREATE TABLE IF NOT EXISTS fin_gl_journal_headers (
    journal_header_id            SERIAL PRIMARY KEY,
    journal_number               VARCHAR(30) UNIQUE NOT NULL,
    journal_name                 VARCHAR(150),
    ledger_id                    INTEGER REFERENCES fin_ledgers(ledger_id),
    period_id                    INTEGER REFERENCES fin_reporting_periods(period_id),
    journal_date                 DATE NOT NULL,
    journal_source               VARCHAR(30),
    journal_category             VARCHAR(30),
    total_debit                  NUMERIC(15,2),
    total_credit                 NUMERIC(15,2),
    status                       VARCHAR(20) DEFAULT 'POSTED',
    created_by                   INTEGER REFERENCES hcm_persons(person_id),
    approved_by                  INTEGER REFERENCES hcm_persons(person_id),
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_gl_journal_headers_ledger_id ON fin_gl_journal_headers(ledger_id);
CREATE INDEX IF NOT EXISTS idx_fin_gl_journal_headers_period_id ON fin_gl_journal_headers(period_id);


-- F9: GL journal lines with account + cost centre
CREATE TABLE IF NOT EXISTS fin_gl_journal_lines (
    journal_line_id              SERIAL PRIMARY KEY,
    journal_header_id            INTEGER REFERENCES fin_gl_journal_headers(journal_header_id) ON DELETE RESTRICT,
    line_number                  INTEGER NOT NULL,
    account_code_id              INTEGER REFERENCES fin_account_codes(account_code_id) ON DELETE RESTRICT,
    cost_centre_id               INTEGER REFERENCES fin_cost_centres(cost_centre_id) ON DELETE RESTRICT,
    debit_amount                 NUMERIC(15,2) DEFAULT 0,
    credit_amount                NUMERIC(15,2) DEFAULT 0,
    description                  VARCHAR(255),
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_gl_journal_lines_journal_header_id ON fin_gl_journal_lines(journal_header_id);
CREATE INDEX IF NOT EXISTS idx_fin_gl_journal_lines_account_code_id ON fin_gl_journal_lines(account_code_id);
CREATE INDEX IF NOT EXISTS idx_fin_gl_journal_lines_cost_centre_id ON fin_gl_journal_lines(cost_centre_id);


-- F10: GL summary balances (derived from journal lines, not directly updated)
CREATE TABLE IF NOT EXISTS fin_gl_balances (
    balance_id                   SERIAL PRIMARY KEY,
    cost_centre_id               INTEGER REFERENCES fin_cost_centres(cost_centre_id),
    account_code_id              INTEGER REFERENCES fin_account_codes(account_code_id),
    period_name                  VARCHAR(20) NOT NULL,
    fiscal_year                  INTEGER,
    fiscal_quarter               INTEGER,
    period_debit                 NUMERIC(15,2),
    period_credit                NUMERIC(15,2),
    period_net                   NUMERIC(15,2),
    begin_balance                NUMERIC(15,2),
    end_balance                  NUMERIC(15,2),
    currency                     VARCHAR(3) DEFAULT 'GBP',
    created_at                TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_fin_gl_balances_cost_centre_id ON fin_gl_balances(cost_centre_id);
CREATE INDEX IF NOT EXISTS idx_fin_gl_balances_account_code_id ON fin_gl_balances(account_code_id);
CREATE INDEX IF NOT EXISTS idx_fin_gl_balances_period_name ON fin_gl_balances(period_name);


-- F11: Budget version control (original, revised, forecast)
CREATE TABLE IF NOT EXISTS fin_budget_versions (
    budget_version_id            SERIAL PRIMARY KEY,
    version_name                 VARCHAR(50) NOT NULL,
    version_type                 VARCHAR(20) DEFAULT 'ORIGINAL',
    fiscal_year                  INTEGER NOT NULL,
    status                       VARCHAR(20) DEFAULT 'APPROVED',
    created_at                TIMESTAMP DEFAULT NOW()
);


-- F12: Budget headers per ledger
CREATE TABLE IF NOT EXISTS fin_budget_headers (
    budget_header_id             SERIAL PRIMARY KEY,
    budget_name                  VARCHAR(100) NOT NULL,
    ledger_id                    INTEGER REFERENCES fin_ledgers(ledger_id),
    budget_version_id            INTEGER REFERENCES fin_budget_versions(budget_version_id),
    fiscal_year                  INTEGER NOT NULL,
