-- ================================================================
--   LEGACY COMPATIBILITY: Views matching old 5-table schema
--   so existing tools/queries still work
-- ================================================================

-- View: hcm_employees (maps to hcm_persons + hcm_assignments)
CREATE OR REPLACE VIEW hcm_employees AS
SELECT
    p.person_id                AS employee_id,
    p.person_number            AS employee_number,
    pn.first_name || ' ' || pn.last_name AS full_name,
    pe.email_address           AS email,
    d.dept_name                AS department,
    a.job_title,
    g.grade_code               AS grade_level,
    a.salary,
    ep.start_date              AS hire_date,
    ep.end_date                AS termination_date,
    a.employment_status        AS employment_status,
    l.location_name            AS location,
    a.manager_person_id        AS manager_id,
    a.dept_id,
    a.position_id,
    a.grade_id,
    a.location_id,
    p.nationality,
    p.date_of_birth,
    p.gender,
    p.created_at
FROM hcm_persons p
LEFT JOIN hcm_person_names pn ON pn.person_id = p.person_id
    AND pn.effective_to IS NULL AND pn.name_type = 'GLOBAL'
LEFT JOIN hcm_person_emails pe ON pe.person_id = p.person_id AND pe.is_primary = TRUE
LEFT JOIN hcm_assignments a ON a.person_id = p.person_id
    AND a.assignment_type = 'PRIMARY' AND a.assignment_status = 'ACTIVE'
LEFT JOIN hcm_employment_periods ep ON ep.person_id = p.person_id
    AND ep.status = 'ACTIVE'
LEFT JOIN hcm_departments d ON d.dept_id = a.dept_id
LEFT JOIN hcm_grades g ON g.grade_id = a.grade_id
LEFT JOIN hcm_locations l ON l.location_id = a.location_id;

-- View: procurement_quotations (maps to proc_quotation_headers + proc_quote_versions)
CREATE OR REPLACE VIEW procurement_quotations AS
SELECT
    qh.quotation_header_id     AS quotation_id,
    qh.engagement_id,
    qh.engagement_name,
    s.supplier_name,
    qh.original_amount,
    qh.revised_amount,
    qv.version_number          AS quotation_version,
    COALESCE(qv.status, qh.status) AS status,
    COALESCE(qv.submitted_date, qh.submission_date) AS submission_date,
    qh.category,
    qh.supplier_id,
    qh.created_at
FROM proc_quotation_headers qh
LEFT JOIN sup_suppliers s ON s.supplier_id = qh.supplier_id
LEFT JOIN proc_quote_versions qv ON qv.quotation_header_id = qh.quotation_header_id;

-- View: procurement_purchase_orders (maps to proc_po_headers)
CREATE OR REPLACE VIEW procurement_purchase_orders AS
SELECT
    ph.po_header_id            AS po_id,
    ph.po_number,
    s.supplier_name,
    ph.total_amount,
    ph.approved_amount,
    ph.status,
    ph.created_date,
    ph.approved_date,
    cc.cost_centre_code        AS cost_centre,
    ph.category,
    ph.supplier_id,
    ph.buyer_id,
    ph.created_at
FROM proc_po_headers ph
LEFT JOIN sup_suppliers s ON s.supplier_id = ph.supplier_id
LEFT JOIN proc_po_distributions pd ON pd.po_line_id = (
    SELECT pl.po_line_id FROM proc_po_lines pl WHERE pl.po_header_id = ph.po_header_id LIMIT 1
)
LEFT JOIN fin_cost_centres cc ON cc.cost_centre_id = pd.cost_centre_id;

